mapper.select:
SELECT p.patient_id AS patientId, p.patient_name AS patientName, p.gender AS gender, CASE p.gender WHEN 1 THEN '男' WHEN 2 THEN '女' ELSE '未知' END AS genderText, p.age AS age, p.inpatient_no AS inpatientNo, p.ward_id AS wardId, w.ward_name AS wardName, p.bed_id AS bedId, b.bed_no AS bedNo, p.risk_level AS riskLevel, CASE p.risk_level WHEN 1 THEN '低危' WHEN 2 THEN '中危' WHEN 3 THEN '中高危' WHEN 4 THEN '高危' ELSE '未知' END AS riskLevelText, p.patient_status AS patientStatus, CASE p.patient_status WHEN 1 THEN '住院中' WHEN 2 THEN '出院' WHEN 3 THEN '居家随访' ELSE '未知' END AS patientStatusText, p.primary_diagnosis AS primaryDiagnosis, p.ecg_count AS ecgCount, p.latest_ecg_time AS latestEcgTime FROM patient_info p LEFT JOIN sys_ward w ON p.ward_id = w.ward_id AND w.is_deleted = 0 LEFT JOIN sys_bed b ON p.bed_id = b.bed_id AND b.is_deleted = 0 WHERE p.is_deleted = 0
AND ( p.patient_name LIKE CONCAT('%', #{req.keyword}, '%') OR p.inpatient_no LIKE CONCAT('%', #{req.keyword}, '%') )
AND ( w.ward_name = #{req.ward} OR CAST(p.ward_id AS CHAR) = #{req.ward} )
AND p.risk_level = #{riskLevelCode}
AND p.patient_status = #{patientStatusCode}
ORDER BY p.update_time DESC, p.patient_id DESC
